710	template <class NodeOp, class... ChildOps>
711	struct Sm90TreeVisitor : Sm90VisitorImpl<ChildOps..., NodeOp> {
712	
713	  using Impl = Sm90VisitorImpl<ChildOps..., NodeOp>;
714	  using Params = typename Impl::Params;
715	  using SharedStorage = typename Impl::SharedStorage;
716	
717	  CUTLASS_HOST_DEVICE
718	  Sm90TreeVisitor() {}
719	
720	  CUTLASS_HOST_DEVICE
721	  Sm90TreeVisitor(
722	      Params const& params,
723	      SharedStorage const& shared_storage)
724	    : Impl(params, shared_storage) {}
725	
726	  template<class CallbacksImpl>
727	  struct ConsumerStoreCallbacks : CallbacksImpl {
728	    CUTLASS_DEVICE
729	    ConsumerStoreCallbacks(CallbacksImpl&& impl)
730	      : CallbacksImpl(cute::forward<CallbacksImpl>(impl)) {}
731	
732	    using CallbacksImpl::callbacks_tuple;
733	
734	    template <typename ElementAccumulator, int FragmentSize>
735	    CUTLASS_DEVICE auto
736	    visit(Array<ElementAccumulator, FragmentSize> const& frg_acc, int epi_v, int epi_m, int epi_n) {
737	      constexpr int Rm1 = sizeof...(ChildOps);
738	      return cute::detail::tapply(callbacks_tuple,
739	        [&] (auto& child_callbacks) CUTLASS_LAMBDA_FUNC_INLINE {
740	          return child_callbacks.visit(frg_acc, epi_v, epi_m, epi_n); // child ops must be nullary (e.g. loads, trees)
741	        },
742	        [&] (auto&&... frg_inputs) CUTLASS_LAMBDA_FUNC_INLINE {
743	          return get<Rm1>(callbacks_tuple).visit(frg_acc, epi_v, epi_m, epi_n, frg_inputs...);
744	        },
745	        make_seq<Rm1>{} // restrict the transform to R-1 child ops, apply is for node op
746	      );
747	    }
748	  };
749	
750	  template <
751	    bool ReferenceSrc, // do register tensors reference the src or dst layout of the tiled copy
752	    class... Args
753	  >
754	  CUTLASS_DEVICE auto
755	  get_consumer_store_callbacks(ConsumerStoreArgs<Args...> const& args) {
756	    auto callbacks_impl = Sm90VisitorImpl<ChildOps..., NodeOp>::
757	      template get_consumer_store_callbacks<ReferenceSrc>(args);
758	    return ConsumerStoreCallbacks<decltype(callbacks_impl)>(cute::move(callbacks_impl));
759	  }
